function generateUser(overrides){
  var random = java.util.UUID.randomUUID().toString();
  var user = { nome: 'QA Test', email: 'qa.' + random + '@example.com', password: 'Pwd@1234', administrador: 'true' };
  if (overrides) {
    for (var k in overrides) { user[k] = overrides[k]; }
  }
  return user;
}

function generateEmail(){
  return 'qa.' + java.util.UUID.randomUUID().toString() + '@example.com';
}

// exported symbols when the file is read
({ generateUser: generateUser, generateEmail: generateEmail });
